  ('heelevel3-444ca548-moex-00191', 'heelevel3-444ca548', 'heelevel3-444ca548-moex-110-3082b5f1', 'sub-heelevel3-444ca548-02', NULL, 'single_choice', '有關我國公務人員懲處制度，下列何者正確？', '["懲處之種類，包括撤職、休職、降級、減俸、記過及申誡", "懲處之原因，限於違法、廢弛職務或其他失職行為", "懲處原則上不得對之提起行政爭訟，惟對於公務員之基本權利造成侵害者，不在此限", "對於同一原因事實重複施以懲處與懲戒，並不違法 31450、31550 32250、32950 33050 33850"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:55+00:00", "source_pdf_sha1": "b59c20af004e", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "334", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "heelevel3", "civil_category": "農業行政"}'::jsonb, NULL),
